sql:
SELECT season_name
FROM seasons
WHERE season_id = (SELECT season_id FROM games WHERE game_id = 1);

external_knowledge:
- The player performance index is a calculated metric that takes into account the player's efficiency, the team's offensive and defensive ratings, and the game's pace; 
- The efficiency rating is a measure of a team's or player's performance, with higher ratings indicating better performance;
- The pace of a game refers to the number of possessions per 48 minutes.

sql:
SELECT game_id, offensive_rating, defensive_rating
FROM game_stats
WHERE game_id = 1;

SELECT game_id, MAX(points_scored) AS highest_points_scored
FROM game_stats
WHERE game_id = 1;

SELECT COUNT(DISTINCT date) AS number_of_games
FROM games
WHERE game_type = 'regular season';

SELECT AVG(points_scored) AS average_points_scored
FROM player_stats
WHERE player_id = 1 AND game_id = 1;
